const item = $input.first().json;

// Betreff nach REF-ID durchsuchen
const subject = item.Subject || item.subject || '';
const refMatch = subject.match(/\[REF:(\d+)\]/i);

if (!refMatch) {
  // Keine REF-ID gefunden - kein Rückfrage-Loop
  return [{
    json: {
      ...item,
      ref_id: null,
      ist_rueckfrage: false
    }
  }];
}

return [{
  json: {
    ...item,
    ref_id: parseInt(refMatch[1]),
    ist_rueckfrage: true,
    antwort_text: item.text || item.snippet || ''
  }
}];ok

const bewerbung = $input.first().json;
const antwortText = $('REF ID extrahieren').first().json.antwort_text;
const emailFrom = $('REF ID extrahieren').first().json.From || 
                  $('REF ID extrahieren').first().json.from?.value?.[0]?.address || '';

// Fehlende Felder aus der Antwort extrahieren via Regex
let verfuegbarkeit = bewerbung.verfuegbarkeit_stunden_pro_woche;
let berufserfahrung = bewerbung.berufserfahrung_jahre;
let plzWohnort = bewerbung.plz_wohnort;

// Verfuegbarkeit aus Antwort extrahieren
if (!verfuegbarkeit) {
  const match = antwortText.match(/(\d+)\s*(?:Stunden?|h|Std)(?:\s*(?:pro|\/)\s*Woche)?/i);
  if (match) verfuegbarkeit = parseInt(match[1]);
}

// Berufserfahrung aus Antwort extrahieren
if (!berufserfahrung) {
  const match = antwortText.match(/(\d+)\s*(?:Jahre?|Jahren)/i);
  if (match) berufserfahrung = parseInt(match[1]);
}

// PLZ aus Antwort extrahieren
if (!plzWohnort) {
  const match = antwortText.match(/\b(\d{5})\b/);
  if (match) plzWohnort = match[1].substring(0, 2);
}

const now = new Date().toISOString();

return [{
  json: {
    ...bewerbung,
    verfuegbarkeit_stunden_pro_woche: verfuegbarkeit,
    berufserfahrung_jahre: berufserfahrung,
    plz_wohnort: plzWohnort,
    email_from: emailFrom || bewerbung.email,
    letzte_aktion: now,
    historie: JSON.stringify([
      ...JSON.parse(bewerbung.historie || '[]'),
      {action: 'rueckfrage_beantwortet', timestamp: now}
    ])
  }
}];

